def process_graph(graph_data):
    graph_copy = graph_data.copy()
    graph_copy.add_node('new_EK_PACKET_SWITCH_58', name='new_EK_PACKET_SWITCH_58', type=['EK_PACKET_SWITCH'])
    graph_copy.add_edge('ju1.a2.m1', 'new_EK_PACKET_SWITCH_58', type=['RK_CONTAINS'])

    direct_children = []
    for child in graph_copy.successors('ju1.a2.m1'):
        edge_data = graph_copy.get_edge_data('ju1.a2.m1', child)
        if edge_data and 'RK_CONTAINS' in edge_data.get('type', []):
            direct_children.append(child)

    child_capacities = []
    for child in direct_children:
        total = 0
        queue = [child]
        visited = set([child])
        while queue:
            node_id = queue.pop(0)
            node_attrs = graph_copy.nodes[node_id]
            if 'type' in node_attrs and 'EK_PORT' in node_attrs['type']:
                total += node_attrs.get('physical_capacity_bps', 0)
            for succ in graph_copy.successors(node_id):
                if succ not in visited:
                    e_data = graph_copy.get_edge_data(node_id, succ)
                    if e_data and 'RK_CONTAINS' in e_data.get('type', []):
                        visited.add(succ)
                        queue.append(succ)
        child_capacities.append((child, total))

    sorted_children = sorted(child_capacities, key=lambda x: x[1], reverse=True)
    graph_json = nx.readwrite.json_graph.node_link_data(graph_copy)
    return_object = {
        'type': 'list',
        'data': [list(item) for item in sorted_children],
        'updated_graph': graph_json
    }
    return return_object

